import (
	"net/http"
	"strings"

	web "code.in.spdigital.sg/sp-digital/golang/web.v2"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/bp"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/pkg/sap"
)

// RetrieveAccounts handles requests to retrieve account details
func RetrieveAccounts(w http.ResponseWriter, r *http.Request) error {
	ctx := r.Context()

	// Extract bp details
	bpDetails := bp.DetailsFromRequest(r)
	if bpDetails == nil ||
		strings.TrimSpace(bpDetails.JWT.Sub) == "" {
		return web.WithStack(ErrIamIDEmpty)
	}

	// Get query params
	accNos := r.URL.Query()["account_number"]
	if len(accNos) <= 0 {
		return web.WithStack(ErrAccountNumberEmpty)
	}

	result := AccountsResponse{
		Data: []AccountsResponseData{},
	}

	for _, accNo := range accNos {
		p, a, found := findPremisesAccount(*bpDetails, accNo)
		if !found {
			return web.WithStack(ErrAccountInvalid)
		}

		result.Data = append(result.Data, newAccountsResponseData(p, a))
	}

	web.RespondJSON(ctx, w, result, nil)
	return nil
}

// newAccountsResponseData returns an AccountsResponseData based on the provided premises and accounts details
func newAccountsResponseData(p bp.PremisesType, acc bp.AccountsType) AccountsResponseData {
	return AccountsResponseData{
		AccountNumber: acc.AccountNumber,
		System:        acc.System,
		PremiseNumber: acc.PremiseNumber,
		AccountStatus: acc.AccountStatus,
		AccountType:   acc.AccountType,
		BpNumber:      acc.BpNumber,
		Address:       acc.Address,
		MailingAddress: AccountsResponseMailingAddress{
			BlockOrApartment: acc.MailingAddress.BlockOrApartment,
			Street:           acc.MailingAddress.Street,
			PostalCode:       acc.MailingAddress.PostalCode,
			Unit:             acc.MailingAddress.Unit,
		},
		Utilities:  acc.Utilities,
		Owner:      p.SharedResourceDetails.Owner,
		OwnerIamID: p.SharedResourceDetails.OwnerIamID,
		OwnerName:  p.SharedResourceDetails.OwnerName,
	}
}

// findPremisesAccount finds the bp.PremisesType and bp.AccountsType of the provided account number from the  bp.Details
func findPremisesAccount(d bp.Details, accNo string) (bp.PremisesType, bp.AccountsType, bool) {
	for _, itp := range d.Premises {
		for _, ita := range itp.Accounts {
			if sap.PadAccountNo(ita.AccountNumber) == sap.PadAccountNo(accNo) {
				return itp, ita, true
			}
		}
	}
	return bp.PremisesType{}, bp.AccountsType{}, false
}

