func TestLinkComplete(t *testing.T) {
	// Given:
	r := httptest.NewRequest(http.MethodPost, "/v3/account/link", testhelpers.NewJSONReader(nil))
	w := httptest.NewRecorder()

	// Mocks:
	details := bp.Details{
		JWT: jwtClaims,
	}
	r = bp.ProvidesDetails(details, r)
	ctx := r.Context()
	ctx = authc.ProvidesJWT(ctx, jwtClaims)

