		Variables: oneupapi.CompleteActivityVariables{
			AccountID:   iamID,
			QuestID:     QuestID,
			CompletedAt: nowSGT().Format(time.RFC3339),
		},
	}
	require.NoError(t, expected1UpReq.Format())
	ctx = oneupapi.MockCompleteActivity(ctx, &expected1UpReq, oneupapi.CompleteActivityResponse{}, nil)
	r = r.WithContext(ctx)

	// When:
	err := LinkComplete(w, r)

	// Then:
	require.NoError(t, err)
	resp := web.Success{}
	testhelpers.ParseJSONResponse(t, w.Result(), &resp)
	require.Equal(t, resp.Message, "Successfully completed link utilities challenge.")

}

