func init() {
	var err error
	client, err = redis.NewClient(context.Background(), os.Getenv("REDIS_URL"))
	if err != nil {
		log.Fatalf("%s", errors.Wrap(err, "redis"))
	}
}

// saveCache saves the bp details into the cache layer
func saveCache(key string, d Details, expiration time.Duration) error {
	if skipCache(key) {
		loglib.GetLogger(context.Background()).Infof("Skipping cache for user %s", key)
		return nil
	}

	jsonStr, err := json.Marshal(d)
	if err != nil {
		return web.NewError(ErrCacheSave, err.Error())
	}

	err = client.Set(key, string(jsonStr), expiration)
	if err == redis.NilReply {
		return web.NewError(ErrCacheSave, "redis nil reply $-1")
	}
	if err != nil {
		return web.NewError(ErrCacheSave, err.Error())
	}

	return nil
}

// removeCache removes the bp details from the cache layer based on key
func removeCache(key string) error {
	_, err := client.Del(key)
	if err != nil {
		return web.NewError(ErrCacheRemove, err.Error())
	}
	return nil
}

// getCache gets the bp details from the cache layer based on the key
func getCache(key string) (Details, error) {
	val, err := client.Get(key)
	if err == redis.NilReply {
		return Details{}, redis.NilReply
	}
	if err != nil {
		return Details{}, web.NewError(ErrCacheGet, err.Error())
	}

	var d Details
	if err = json.Unmarshal([]byte(val), &d); err != nil {
		return Details{}, web.NewError(ErrCacheGet, err.Error())
	}
	return d, nil
}

