// SaveCache saves the bp details into the cache layer
func SaveCache(key string, d Details) error {
	if os.Getenv("APPENV") != "test" {
		log.Fatalf("NOT for use in APPENV=" + os.Getenv("APPENV"))
	}
	return saveCache(key, d, time.Duration(5*time.Second))
}

// RemoveCache removes the bp details from the cache layer based on key
func RemoveCache(keys ...string) error {
	if os.Getenv("APPENV") != "test" {
		log.Fatalf("NOT for use in APPENV=" + os.Getenv("APPENV"))
	}
	for _, key := range keys {
		if err := removeCache(key); err != nil {
			return err
		}
	}
	return nil
}

// GetCache gets the bp details from cache layer based on key
func GetCache(key string) (Details, error) {
	if os.Getenv("APPENV") != "test" {
		log.Fatalf("NOT for use in APPENV=" + os.Getenv("APPENV"))
	}
	return getCache(key)
}

