func TestSubmit(t *testing.T) {
	t.Parallel()
	testCases := []struct {
		lastActualRead string
		preDecPlace    string
		decPlace       string
		lowerLimit     string
		upperLimit     string
		reading        float64
	}{
		{"9,800", "04", "00", "9,800", "100", 9800},
		{"9,800", "04", "00", "9,800", "100", 9801},
		{"9,800", "04", "00", "9,800", "100", 99},
		{"9,800", "04", "00", "9,800", "100", 100},
		{"20,000", "05", "00", "20,000", "20,002", 20000},
		{"20,000", "05", "00", "20,000", "20,002", 20001},
		{"20,000", "05", "00", "20,000", "20,002", 20002},
		{"9,800.0", "04", "01", "9,800.0", "100", 9800},
		{"9,800.0", "04", "01", "9,800.0", "100", 9800.1},
		{"9,800.0", "04", "01", "9,800.0", "100", 99.9},
		{"9,800.0", "04", "01", "9,800.0", "100", 100},
		{"20,000.5", "05", "01", "20,000.5", "20,000.7", 20000.5},
		{"20,000.5", "05", "01", "20,000.5", "20,000.7", 20000.6},
		{"20,000.5", "05", "01", "20,000.5", "20,000.7", 20000.7},
		{"99,999.0", "05", "01", "", "20,000.7", 99999.0},
		{"99,999.0", "05", "01", "", "20,000.7", 99999.1},
		{"99,999.0", "05", "01", "", "20,000.7", 1.0},
		{"99,999.0", "05", "01", "1.0", "", 99999.0},
		{"99,999.0", "05", "01", "1.0", "", 99999.1},
		{"100.0", "05", "01", "9,999.0", "100.0", 9998.0}, // Lower limit higher than upper limit, below lower limit
		{"100.0", "05", "01", "9,999.0", "100.0", 100.1},  // Above upper limit
		{"", "01", "01", "", "", 1.0},
		{"", "01", "01", "", "1.0", 1.0},
		{"", "01", "01", "", "1.1", 1.0},
	}
	for _, tc := range testCases {
		t.Run(fmt.Sprintf("%f", tc.reading), func(t *testing.T) {

			// mock time
			timeSGT := timeutil.NowSGT()
			nowSGT = func() time.Time {
				return time.Date(timeSGT.Year(), timeSGT.Month(), timeSGT.Day(), 00, 00, 00, 000, timeutil.SGT)
			}
			defer func() {
				time.Sleep(time.Millisecond * 100)
				nowSGT = timeutil.NowSGT
			}()
			// Given:
			ebsAccNo := "EBS_ACCNO"
			msslAccNo := "MSSL_ACCNO"
			ua := "Friday/1.0.0 (Android)"
			// Submission token
			elec := testSubmissionDetails(t, meterreaddetails.UtilTypeElectric)
			// Given test cases
			elec.PreDecPlace.String = tc.preDecPlace
			elec.DecPlace.String = tc.decPlace
			elec.LowerLimit.String = tc.lowerLimit
			elec.UpperLimit.String = tc.upperLimit
			elec.LastActualRead.String = tc.lastActualRead
			gas := testSubmissionDetails(t, meterreaddetails.UtilTypeGas)
			water := testSubmissionDetails(t, meterreaddetails.UtilTypeWater)
			details := smrd.SubmissionDetails{
				ebsAccNo:  []meterreaddetails.ItemType{gas, water},
				msslAccNo: []meterreaddetails.ItemType{elec},
			}
			submissionToken, err := smrd.CreateSubmissionToken(ua, details)
			assert.NoError(t, err)
			// Request payload
			w, r := createSubmitHTTPRequest(ua, createJWTDetail(ebsAccNo, msslAccNo), SubmitRequest{
				SubmissionToken: submissionToken,
				Readings: []ReadingsType{
					{MeterID: "DEVICE1", Value: fmt.Sprintf("%f", tc.reading), ImageRefID: "UUID3", SubmitMode: "3", ContactNo: "12345678"},
					{MeterID: "DEVICE2", Value: "600", ImageRefID: "UUID1", SubmitMode: "1", ContactNo: "12345678"},
					{MeterID: "DEVICE3", Value: "20000", ImageRefID: "UUID2", SubmitMode: "2", ContactNo: "12345678"},
				},
			})

			// Expected:
			// - Based on submit request and submission token
			expectedEBSReq := uportalaccountmanagement.SubmitMeterReadingRequest{
				AccNo: sap.StripAccountNo(ebsAccNo),
				MeterReadData: uportalaccountmanagement.SubmitMeterReadingMeterReadData{
					Item: []uportalaccountmanagement.SubmitMeterReadingItem{
						{PreDecPlace: "600", DecPlace: "", DeviceNo: gas.DeviceNo.String, UtilType: gas.UtilType.String, Source: "19", ImageRefID: "UUID1", SubmitMode: "1", ContactNo: "12345678"},
						{PreDecPlace: "20000", DecPlace: "0", DeviceNo: water.DeviceNo.String, UtilType: water.UtilType.String, Source: "19", ImageRefID: "UUID2", SubmitMode: "2", ContactNo: "12345678"},
					},
				},
			}
			elecPreDecPlace, elecDecPlace, _ := splitIntDecimal(meterreaddetails.UtilTypeElectric, tc.reading, tc.decPlace)
			expectedMSSLReq := uportalaccountmanagement.SubmitMeterReadingRequest{
				AccNo: sap.StripAccountNo(msslAccNo),
				MeterReadData: uportalaccountmanagement.SubmitMeterReadingMeterReadData{
					Item: []uportalaccountmanagement.SubmitMeterReadingItem{
						{PreDecPlace: elecPreDecPlace, DecPlace: elecDecPlace, DeviceNo: elec.DeviceNo.String, UtilType: elec.UtilType.String, Source: "19", ImageRefID: "UUID3", SubmitMode: "3", ContactNo: "12345678"},
					},
				},
			}

			// Mocks:
			ctx := r.Context()
			mockResp := uportalaccountmanagement.SubmitMeterReadingResponse{}
			testhelpers.UnmarshalJSONFile(&mockResp, "internal/stubs/frcportal/uportalaccountmanagement/testdata/submitmeterreading/success.json")
			ctx = uportalaccountmanagement.MockSubmitMeterReading(ctx, &expectedEBSReq, mockResp, nil)
			ctx = uportalaccountmanagement.MockSubmitMeterReading(ctx, &expectedMSSLReq, mockResp, nil)

			mock1upCompletionRequest := oneupapi.CompleteActivityRequest{
				Variables: oneupapi.CompleteActivityVariables{
					AccountID:   iamID,
					QuestID:     SUBMIT_METER_QUEST,
					CompletedAt: time.Date(timeSGT.Year(), timeSGT.Month(), timeSGT.Day(), 00, 00, 00, 000, timeutil.SGT).Format(time.RFC3339),
				},
			}
			require.NoError(t, mock1upCompletionRequest.Format())
			ctx = oneupapi.MockCompleteActivity(ctx, &mock1upCompletionRequest, oneupapi.CompleteActivityResponse{}, nil)
			r = r.WithContext(ctx)

			// When:
			err = Submit(w, r)

			// Then:
			assert.NoError(t, err)
			result := web.Success{}
			testhelpers.ParseJSONResponse(t, w.Result(), &result)

			assert.Contains(t, result.Message, "Your next submission window")
		})
	}
}

func TestSubmit_ValidationError(t *testing.T) {
	t.Parallel()
	testCases := []struct {
		lastActualRead string
		decPlace       string
		lowerLimit     string
		upperLimit     string
		reading        string
	}{
		{"100.0", "01", "100.0", "100.1", "99.9"},    // Below lower limit
		{"100.0", "01", "100.0", "200.0", "INVALID"}, // Invalid number
		{"100.0", "01", "", "200.0", "99.9"},         // No lower limit, below last actual read
		{"100.0", "01", "100.0", "", "99.9"},         // No upper limit, below last actual read
	}

	for _, tc := range testCases {
		t.Run(tc.reading, func(t *testing.T) {
			// Given:
			ebsAccNo := "EBS_ACCNO"
			ua := "Friday/1.0.0 (Android)"
			// Submission token
			elec := testSubmissionDetails(t, meterreaddetails.UtilTypeElectric)
			// Given test cases
			elec.DecPlace.String = tc.decPlace
			elec.LowerLimit.String = tc.lowerLimit
			elec.UpperLimit.String = tc.upperLimit
			elec.LastActualRead.String = tc.lastActualRead
			details := smrd.SubmissionDetails{
				ebsAccNo: []meterreaddetails.ItemType{elec},
			}
			submissionToken, err := smrd.CreateSubmissionToken(ua, details)
			assert.NoError(t, err)
			// Request payload
			w, r := createSubmitHTTPRequest(ua, createJWTDetail(ebsAccNo, ""), SubmitRequest{
				SubmissionToken: submissionToken,
				Readings: []ReadingsType{
					{MeterID: "DEVICE1", Value: tc.reading},
				},
			})

			// When:
			err = Submit(w, r)

			// Then:
			expected := smrd.ErrSubmitReadingInvalid
			testhelpers.AssertWebError(t, expected.Status, expected.Code, err)
		})
	}
}

