func TestGetElecSubmission(t *testing.T) {
	testCases := []struct {
		given          []uportalaccountmanagement.SubmitMeterReadingResponse
		expected       uportalaccountmanagement.SubmitMeterReadingRespItem
		expectedStatus bool
	}{
		{
			given: []uportalaccountmanagement.SubmitMeterReadingResponse{
				{
					ResponseData: uportalaccountmanagement.SubmitMeterReadingResponseData{
						RespMeterReadData: uportalaccountmanagement.SubmitMeterReadingRespMeterReadData{
							Item: []uportalaccountmanagement.SubmitMeterReadingRespItem{
								{UtilType: meterreaddetails.UtilTypeGas},
								{UtilType: meterreaddetails.UtilTypeWater},
							},
						},
					},
				},
			},
			expected:       uportalaccountmanagement.SubmitMeterReadingRespItem{},
			expectedStatus: false,
		},
		{
			given: []uportalaccountmanagement.SubmitMeterReadingResponse{
				{
					ResponseData: uportalaccountmanagement.SubmitMeterReadingResponseData{
						RespMeterReadData: uportalaccountmanagement.SubmitMeterReadingRespMeterReadData{
							Item: []uportalaccountmanagement.SubmitMeterReadingRespItem{
								{UtilType: meterreaddetails.UtilTypeGas},
								{UtilType: meterreaddetails.UtilTypeElectric},
							},
						},
					},
				},
			},
			expected:       uportalaccountmanagement.SubmitMeterReadingRespItem{UtilType: meterreaddetails.UtilTypeElectric},
			expectedStatus: true,
		},
	}

	for i, tc := range testCases {
		tc := tc
		t.Run(strconv.Itoa(i), func(t *testing.T) {
			t.Parallel()

			// When:
			result, status := getElecSubmission(tc.given)

			// Then:
			require.Equal(t, tc.expectedStatus, status)
			require.Equal(t, tc.expected, result)
		})
	}
}

