						},
					},
				},
			},
			expected:       uportalaccountmanagement.SubmitMeterReadingRespItem{UtilType: meterreaddetails.UtilTypeElectric},
			expectedStatus: true,
		},
	}

	for i, tc := range testCases {
		tc := tc
		t.Run(strconv.Itoa(i), func(t *testing.T) {
			t.Parallel()

			// When:
			result, status := getElecSubmission(tc.given)

			// Then:
			require.Equal(t, tc.expectedStatus, status)
			require.Equal(t, tc.expected, result)
		})
	}
}

