package v1

import (
	"code.in.spdigital.sg/sp-digital/golang/web.v2/middleware"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v1/digitalsigning"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/authc"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/pkg/handler"
	"github.com/go-chi/chi/v5"
)

// Public request to access this routes via Public Mulesoft Gateway
func public(r chi.Router) {

	//Digital Signing
	r.Post("/v1/public/signtoken", handler.Wrap(digitalsigning.DigitalSiging))
}

func authenticatedRoutes(r chi.Router) {
	r.Group(func(r chi.Router) {
		//Digital Signing
		r.Post("/v1/signtoken", handler.Wrap(digitalsigning.DigitalSiging))
	})
}

// GatewayAuthenticatedRoutes is the authenticated gateway routes behind b2c mulesoft
func GatewayAuthenticatedRoutes(r chi.Router) {
	// Middlewares
	r.Use(middleware.LimitPayload(10000)) //10 KB

	// Parse JWTClaims from SecurityContext and store in Context
	r.Use(authc.JWTClaimsSecurityContextMiddleware())

	// Routes
	authenticatedRoutes(r)
}

// GatewayPublicRoutes is the gateway public routes behind heimdall-public mulesoft
func GatewayPublicRoutes(r chi.Router) {
	// Middlewares
	r.Use(middleware.LimitPayload(10000)) //10 KB

	r.Group(public)
}

package usage

import (
	"net/http"
	"time"

	web "code.in.spdigital.sg/sp-digital/golang/web.v2"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/bp"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/pkg/numutil"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/pkg/timeutil"
	"github.com/go-chi/chi/v5"
	"golang.org/x/sync/errgroup"
)

// Charts returns all usage and peer comparison data filtered by premise
// and grouped by utilities
func Charts(w http.ResponseWriter, r *http.Request) error {
	ctx := r.Context()

	// Extract bp details
	bpDetails := bp.DetailsFromRequest(r)

	// Extract premise ID
	premiseID := chi.URLParam(r, "premises_id")
	// Validate authorization on premise ID
	p, err := bpDetails.HasPremises(premiseID)
	if err != nil {
		return web.WithStack(err)
	}

	// Retrieve premise accounts' usage
	g := &errgroup.Group{}

	// Get billed usage data
	hcChan := AsyncRetrieveBilledUsage(ctx, g, p)

	// Get peer comparison data
	pcChan := asyncRetrievePeerComparison(ctx, g, p)

	if err := g.Wait(); err != nil {
		return web.WithStack(err)
	}
	hcData := <-hcChan
	pcData := <-pcChan

	// Merge billed usage and peer comparison data points
	result := ChartsResponse{
		// Server time
		ServerTime: timeutil.NowSGT().Format(time.RFC3339),
		// Use peer comparison's premises type
		PremiseType: pcData.PremiseType,
		Elec:        mergeChartData(hcData.Elec, pcData.Elec),
		Gas:         mergeChartData(hcData.Gas, pcData.Gas),
		Water:       mergeChartData(hcData.Water, pcData.Water),
	}

	web.RespondJSON(ctx, w, result, nil)
	return nil
}

// mergeChartData combines the data points for peer comparison and billed usage data
func mergeChartData(hc, pc ChartData) ChartData {
	result := ChartData{
		AverageConsumption:    hc.AverageConsumption,
		ComparisonType:        pc.ComparisonType,
		ComparisonMessage:     pc.ComparisonMessage,
		ComparisonMessageType: pc.ComparisonMessageType,
	}

	// Convert historical consumption (hc) data points to map in order for us to be able
	// to easily lookup and populate with peer comparison (pcData) data points
	lookup := map[string]DataType{}
	for _, it := range hc.Data {
		period := timeutil.FormatSGT(it.Period, time.RFC3339)
		if _, ok := lookup[period]; ok {
			// Skip dupes
			continue
		}

		// Set peer comparison to zero-value
		it.PeerComparison = PeerComparisonType{}
		// Set data point into lookup map
		lookup[period] = it
	}

	// Merge with peer comparison (pc) data points using the lookup map and
	// setting peer comparison data accordingly
	seen := map[string]bool{}
	for _, it := range pc.Data {
		period := timeutil.FormatSGT(it.Period, time.RFC3339)
		if _, ok := seen[period]; ok {
			// Skip dupes
			continue
		}
		seen[period] = true

		// Lookup same period
		if v, ok := lookup[period]; ok {
			// Merge with peer comparison data into historical consumption data point
			v.PeerComparison = it.PeerComparison
			lookup[period] = v
		} else {
			// Set consumption to zero-value
			it.Consumption = ConsumptionType{}
			// Add peer comparison data point
			lookup[period] = it
		}
	}

	result.Data = []DataType{}
	for _, v := range lookup {
		v.Consumption.Current = numutil.TruncateFloat(v.Consumption.Current, 2)
		v.Consumption.Previous = numutil.TruncateFloat(v.Consumption.Previous, 2)
		v.PeerComparison.Efficient = numutil.TruncateFloat(v.PeerComparison.Efficient, 2)
		v.PeerComparison.Average = numutil.TruncateFloat(v.PeerComparison.Average, 2)
		result.Data = append(result.Data, v)
	}
	result.sort()

	return result
}

