			{Period: timeutil.Date(2017, 7, 1, 0, 0), Unit: utilities.UnitElectric, Status: "", Consumption: ConsumptionType{999.0, 999.0}, PeerComparison: PeerComparisonType{1.123456789, 1.999999999}},
		},
	}

	// When:
	result := mergeChartData(hc, pc)

	// Then:
	expected := ChartData{
		AverageConsumption:    1.0,
		ComparisonMessage:     "PC",
		ComparisonMessageType: "PC",
		ComparisonType:        "PC",
		Data: []DataType{
			{Period: timeutil.Date(2017, 9, 1, 0, 0), Unit: utilities.UnitElectric, Status: utilities.UsageStatusActual, Consumption: ConsumptionType{1.12, 0.0}, PeerComparison: PeerComparisonType{1.12, 1.99}},
			{Period: timeutil.Date(2017, 8, 1, 0, 0), Unit: utilities.UnitElectric, Status: utilities.UsageStatusActual, Consumption: ConsumptionType{1.99, 0.0}, PeerComparison: PeerComparisonType{1.12, 1.99}},
			{Period: timeutil.Date(2017, 7, 1, 0, 0), Unit: utilities.UnitElectric, Status: "", Consumption: ConsumptionType{0.0, 0.0}, PeerComparison: PeerComparisonType{1.12, 1.99}},
			{Period: timeutil.Date(2017, 6, 1, 0, 0), Unit: utilities.UnitElectric, Status: utilities.UsageStatusEstimated, Consumption: ConsumptionType{0.0, 1.0}, PeerComparison: PeerComparisonType{0.0, 0.0}},
		},
	}
	require.Equal(t, expected.AverageConsumption, result.AverageConsumption)
	require.Equal(t, expected.ComparisonMessage, result.ComparisonMessage)
	require.Equal(t, expected.ComparisonMessageType, result.ComparisonMessageType)
	require.Equal(t, expected.ComparisonType, result.ComparisonType)
	assertDataTypeArray(t, expected.Data, result.Data)
}

