func TestRetrieveAccounts(t *testing.T) {
	ownerIamID := "AYAM_RETRIEVE_DETAILS"
	owner := AccountsResponseData{
		System:        "EBS",
		BpNumber:      "1004006729",
		AccountNumber: "008936273922",
		AccountStatus: "Active",
		AccountType:   "DOM",
		PremiseNumber: "2100487140",
		Address:       "12 JBM SINGAPORE 160106",
		MailingAddress: AccountsResponseMailingAddress{
			BlockOrApartment: "12",
			Street:           "JBM",
			Unit:             "",
			PostalCode:       "160106",
		},
		Utilities:  []string{"water"},
		Owner:      true,
		OwnerIamID: ownerIamID,
		OwnerName:  "",
	}

	sharedIamID := "SHAREDIAMID"
	shared := AccountsResponseData{
		System:        "EBS",
		BpNumber:      "1000436916",
		AccountNumber: "008427504205",
		AccountStatus: "Active",
		AccountType:   "DOM",
		PremiseNumber: "2000673915",
		Address:       "475 SEMBAWANG DR",
		MailingAddress: AccountsResponseMailingAddress{
			BlockOrApartment: "475",
			Street:           "S'WANG DR",
			Unit:             "#13-323",
			PostalCode:       "750475",
		},
		Utilities:  []string{"electric", "water"},
		Owner:      false,
		OwnerIamID: sharedIamID,
		OwnerName:  "Hans Ang",
	}

	testCases := []struct {
		given    []string
		expected AccountsResponse
	}{
		{given: []string{owner.AccountNumber}, expected: AccountsResponse{Data: []AccountsResponseData{owner}}},
		{given: []string{shared.AccountNumber}, expected: AccountsResponse{Data: []AccountsResponseData{shared}}},
		{given: []string{owner.AccountNumber, shared.AccountNumber}, expected: AccountsResponse{Data: []AccountsResponseData{owner, shared}}},
		{given: []string{shared.AccountNumber, owner.AccountNumber}, expected: AccountsResponse{Data: []AccountsResponseData{shared, owner}}},
	}

	for _, tc := range testCases {
		t.Run(fmt.Sprintf("%v", tc.given), func(t *testing.T) {

			// Given:
			query := url.Values{"iam_id": []string{ownerIamID}, "account_number": tc.given}
			r := httptest.NewRequest(http.MethodGet, "/v3/user/accounts?"+query.Encode(), nil)
			w := httptest.NewRecorder()
			r = bp.ProvidesDetails(testBPDetails(ownerIamID, owner, sharedIamID, shared), r)

			// When:
			err := RetrieveAccounts(w, r)

			// Then:
			require.NoError(t, err)
			resp := AccountsResponse{}
			testhelpers.ParseJSONResponse(t, w.Result(), &resp)
			require.Equal(t, tc.expected, resp)
		})
	}
}

